var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 제가 고통 받는 동안 처음 보는 아이들과 희희낙락하고 계셨단 말씀이로군요.","JPN":"つまり、私が苦しみを味わっている間、子どもたちと戯れていたというわけですね。","ENG":"So, while I was being tortured, you were entertaining some strange children.","TWN":"所以說，在我受苦的時候，您和初次見面的孩子們都很快樂的意思吧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"매사를 부정적으로 바라보는 건 자네의 나쁜 습관이야.","JPN":"そうやって物事をネガティブに捉えるのは君の悪い癖だ。","ENG":"You look at things so negatively all the time.","TWN":"凡事都持否定態度是你的壞習慣。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무것도 모르는 아이들을 도왔다고 표현해 주면 안 되겠나?","JPN":"何も知らない子どもたちを保護していた、そうだろう？","ENG":"Can't you say that I helped some innocent children instead?","TWN":"能不能好好幫助什麼都不懂的孩子們？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼啊......"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제프티 바이오테크는 신약 개발과 의체 소재 생산으로 두각을 드러낸 바이오 기업입니다.","JPN":"ジェフティ・バイオテックは、新薬の開発と義体素材の生産に長けたバイオ企業です。","ENG":"Jehuty Biotech is a bioengineering company on the rise, specializing in new medicine development and mechanical prosthetic production.","TWN":"傑夫堤生物科技是透過開發新藥和生產假體材料而嶄露頭角的生物技術企業。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최근 투자자들 사이에서 주목 받고 있는 유니콘 기업이죠. 인신매매 얘기는 처음 듣지만요.","JPN":"最近投資家の間でも注目されているユニコーン企業です。人身売買については初耳ですが。","ENG":"It's a unicorn that's gained popularity among business investors. I've never heard of its involvement in human trafficking before, though.","TWN":"這是最近備受投資者關注的獨角獸企業。 雖然第一次聽說販賣人口的事情。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 기업, 본사가 어디에 붙어 있나?","JPN":"その企業、本社はどこにある？","ENG":"Where is it headquartered?","TWN":"那個企業，總公司在哪裡？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"샤레이드 소재입니다. 그로니아 변경에 연구 시설이 있다더군요.","JPN":"所在地はシャレードです。グロニア辺境に研究施設を持っているそうですね。","ENG":"Charade. Its lab is located on the edge of Gronia.","TWN":"位於沙雷得，聽說在葛羅尼亞邊境有研究設施。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로니아라...... 참 그 나라와는 좋은 일로 엮이는 법이 없군.","JPN":"グロニアか……あの国との腐れ縁はなかなか断ち切れないな。","ENG":"Gronia... It seems I have an ill-fated relationship with that country.","TWN":"葛羅尼亞...... 和那個國家每次都牽扯到不好的事情阿。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기다리게. 그 유니콘한테서 연락이 온 모양이야.","JPN":"おっと、噂をすれば……あのユニコーンから連絡が来たようだな。","ENG":"Wait. I've got a phone call from that unicorn.","TWN":"等一下吧，好像那個獨角獸聯繫我們的樣子。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"갑자기 이렇게 연락드려 죄송합니다. 잠시 통화 괜찮으시겠습니까?","JPN":"急なご連絡失礼いたします。少しお時間よろしいでしょうか？","ENG":"We're sorry to contact you on such short notice. May we have a moment of your time, sir?","TWN":"很抱歉這麼突然聯繫，方便和您電話嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"편할 대로 하시게. 소포도 일방적으로 보낸 마당에.","JPN":"今更こっちの都合を聞くのか？　宅急便もいきなり送ってきた君たちが？","ENG":"Go ahead. You already sent me a package without asking me first.","TWN":"你方便就好，包裹也不是隨便寄的嗎。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"그 건에 대해선 드릴 말씀이 없습니다.","JPN":"その件については誠に申し訳ございません。","ENG":"We're sorry for the inconvenience, sir.","TWN":"針對那件事情我無話可說。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"조사 결과, 직원의 실수로 오배송되었다고 합니다. <color=#ffd34c>상품</color>은 저희 측에서 즉시 회수하도록 하겠습니다.","JPN":"こちらでお調べしましたが、誤配送だったようです。<color=#ffd34c>商品</color>はすぐ回収いたします。","ENG":"We found out that one of our employees sent it to you by mistake. We'll send someone to collect the <color=#ffd34c>product</color> at once.","TWN":"經過調查，是我們員工寄錯了。<color=#ffd34c>商品</color>由我們會立即回收的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니. 번거롭게 그럴 필요 없네.","JPN":"いや、その必要はない。","ENG":"No, don't bother.","TWN":"哎呀，沒必要這麼麻煩。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 보내 준 <color=#ffd34c>상품</color>, 마음에 들었어. 가능하면 생산된 동종 모델은 전부 받고 싶군.","JPN":"君たちの<color=#ffd34c>商品</color>、なかなか気に入ったよ。できれば同じ型番のモデルは全部受け取りたいんだが。","ENG":"I like the <color=#ffd34c>product</color> you sent me. If it's possible, I want all the units of the same model.","TWN":"你們寄來的<color=#ffd34c>商品</color>，我很喜歡。如果可以的話，已經生產的同種型號想全部拿到。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"정말이십니까?","JPN":"本当ですか？","ENG":"Are you sure, sir?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};